package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair6616DifferenceFindingTest {

    private final ClonePair6616 subject = new ClonePair6616();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{-720.0, -10};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(((Double) values[0]).doubleValue(), ((Integer) values[1]).intValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(((Double) values[0]).doubleValue(), ((Integer) values[1]).intValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Double(2.671007058389896E-29)",
            null,
            "java.lang.Object[][Double(-720.0),Integer(-10)]",
            "java.lang.Object[][Double(-720.0),Integer(-10)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Double(2.6710070583898965E-29)",
            null,
            "java.lang.Object[][Double(-720.0),Integer(-10)]",
            "java.lang.Object[][Double(-720.0),Integer(-10)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
